import base64
from xml.dom import minidom

class SamlServiceProvider:
    def __init__(self, destination_url):
        self.destination_url = destination_url

    def create_saml_request(self, user_info):
        # Simplified SAML request template for demonstration purposes
        saml_template = """
        <samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                           ID="_1234567890abcdefg" Version="2.0" IssueInstant="{issue_instant}"
                           Destination="{destination_url}">
            <saml:Issuer xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion">{issuer}</saml:Issuer>
            <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified"/>
        </samlp:AuthnRequest>
        """

        from datetime import datetime
        issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
        issuer = user_info.get('issuer', 'https://example.com')
        
        saml_request = saml_template.format(
            issue_instant=issue_instant,
            destination_url=self.destination_url,
            issuer=issuer
        )

        # Encode the SAML request
        encoded_saml_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')

        return f"form-urlencoded:SAMLRequest={encoded_saml_request}"

    def post_saml_request(self, saml_request):
        import requests

        headers = {'Content-Type': 'application/x-www-form-urlencoded'}
        response = requests.post(self.destination_url, data=saml_request, headers=headers)
        
        if response.status_code == 200:
            return "SAML request posted successfully"
        else:
            return f"Failed to post SAML request: {response.status_code} - {response.text}"

